import{_ as o,o as t,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"23. Notice Period Before Termination","description":"","frontmatter":{"title":"23. Notice Period Before Termination","eba":"Nurses and Midwives 2024-2028","topics":["leave","long-service-leave","employment","termination"]},"headers":[],"relativePath":"ebas/nurses-midwives/employment-types/23-notice-period-before-termination.md","filePath":"ebas/nurses-midwives/employment-types/23-notice-period-before-termination.md"}'),r={name:"ebas/nurses-midwives/employment-types/23-notice-period-before-termination.md"};function a(s,e,p,l,m,c){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_23-notice-period-before-termination" tabindex="-1">23. Notice Period Before Termination <a class="header-anchor" href="#_23-notice-period-before-termination" aria-label="Permalink to &quot;23. Notice Period Before Termination&quot;">​</a></h1><p><strong>23.1</strong> Notice Period/ Payment in Lieu</p><p><strong>(a)</strong> An Employer may terminate the employment of an Employee by providing four weeks&#39; notice in writing.</p><p><strong>(b)</strong> The notice required by subclause 23.1(a) will be increased by one week if the Employee is over 45 years of age and has completed more than two years&#39; continuous service.</p><p><strong>(c)</strong> Continuous service for the purpose of this clause has the same meaning as it does under <a href="/eba/ebas/nurses-midwives/leave/70-long-service-leave.html">clause 70</a> (Long Service Leave) and will include prior continuous service preceding a transfer of business, except in respect of any period of continuous service for which notice has already been given or paid.</p><p><strong>(d)</strong> An Employer may make payment in lieu of notice for part or all of the notice period. The payment in lieu of notice must equal or exceed the total of all amounts that the Employer would have paid had the Employee&#39;s employment continued until the end of the required notice period. That payment must be calculated on the basis of:</p><p><strong>(i)</strong> the Employee&#39;s ordinary hours of work (even if not standard hours);</p><p><strong>(ii)</strong> the amounts ordinarily payable to the Employee in respect of those hours, including (for example) allowances, loading and penalties; and</p><p><strong>(iii)</strong> any other amounts payable under the Employee&#39;s contract of employment.</p><p><strong>(e)</strong> An Employee may terminate their employment by providing four weeks&#39; notice to the Employer in writing. Subject to additional financial obligations imposed on the Employer by any legislation, if an Employee fails to give four weeks&#39; notice and the Employer had not agreed to a shorter period of notice, the Employer will have the right to deduct one week&#39;s wages due to the Employee provided that the deduction is not unreasonable in the circumstances.</p><p><strong>(f)</strong> Subclauses 23.1(a) to (d) do not affect an Employer&#39;s right to terminate an Employee&#39;s employment without notice for serious misconduct.</p><p><strong>(g)</strong> Subclauses 23.1(a) to (e) do not apply to:</p><p><strong>(i)</strong> Employees engaged under a fixed term contract;</p><p><strong>(ii)</strong> Employees engaged for a specific period of time or for a specific task or tasks;</p><p><strong>(iii)</strong> trainees whose employment under a traineeship agreement or an approved traineeship is for a specified period or is, for any other reason, limited to the duration of the agreement; or</p><p><strong>(iv)</strong> casual Employees.</p><p><strong>23.2</strong> Time off work during notice period</p><p>Where the Employer has given notice of termination to an Employee, an Employee will be allowed up to one day&#39;s time off without loss of pay for the purpose of seeking other employment. The time off will be taken at times that are convenient to the Employee after consultation with the Employer.</p><p><strong>23.3</strong> Certificate of Service on termination</p><p>A certificate of service including the information at <a href="/eba/ebas/nurses-midwives/appendices/06-template-certificate-of-service.html">Appendix 6</a> will be provided to the Employee wherever practicable within 14 days of the date of termination including where a full-time or part-time Employee terminates employment and becomes a casual Employee.</p><p>Plain language terms: notice period, resignation notice.</p>',21)])])}const h=o(r,[["render",a]]);export{f as __pageData,h as default};
